var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`팀장님! 놈이 인질을 잡고 저항하고 있습니다!`,JPN:`班長！　奴が人質を盾にして抵抗しています！`,ENG:`Sir! He's taken a hostage!`,TWN:`隊長！那傢伙還在反抗，他手裡有人質！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`발포 허가해 주세요! 이번에 놓치면 그동안 고생했던 게 전부 물거품이 됩니다!`,JPN:`発砲を許可してください！　今度逃したら、今までの苦労がすべて水の泡になります！`,ENG:`Please give us the authorization to fire! If we lose him now, all our efforts will have been for nothing!`,TWN:`請允許我開火！這次如果放他走，一直以來的努力都將功虧一簣！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`무슨 헛소리야?!! 인질이 있는데 경찰이 어떻게 발포를 하나!`,JPN:`何を言ってるんだ！？　人質がいるのに警察がどうやって発砲するんだ！`,ENG:`Don't be ridiculous! We're cops! We can't just start shooting when there's a hostage!`,TWN:`你在說什麼蠢話？！！有人質在，員警怎麼可能開火！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`포위망 유지한 채로 어떻게든 인질을 구할 방법을 찾아!`,JPN:`包囲網を維持したまま、なんとか人質を救う方法を探せ！`,ENG:`Keep them surrounded and find a way to secure the hostage!`,TWN:`維持包圍圈，想辦法救出人質！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`보고드립니다! 현재 범인들이 인질을 방패 삼아 포위망을 벗어나려 합니다!`,JPN:`報告します！　現在犯人たちは人質を盾にして包囲網を抜け出そうとしています！`,ENG:`Sir! They're using the hostage as a human shield to slip past the barricades!`,TWN:`報告！犯人試圖把人質當擋箭牌逃離包圍圈！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`제가 막겠습니다! 여기서 눈 뜨고 놓칠 순 없어요!`,JPN:`私が防ぎます！　このまま何もせず逃がすわけにはいきません！`,ENG:`I'll stop them! We can't lose them here!`,TWN:`我去阻止！我不能眼睜睜地看他跑掉！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`뭐? 상대는 카운터라고! 직접 맞서면 안 돼!`,JPN:`いや、相手はカウンターだ！　正面から立ち向かうのは危険だ！`,ENG:`What? They're Counters! You must not engage them directly!`,TWN:`什麼？對手是制裁者！別輕舉妄動！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`당장 현장 이탈해! 도망치라고! 이 멍청한 자식들아!!`,JPN:`今すぐ現場から離脱しろ！　逃げるんだ！　無茶するな！！`,ENG:`Fall back right now! Run, you fools!`,TWN:`馬上離開現場！快跑！你們這些笨蛋！！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:null,text:{KOREA:`사상자 발생! 즉시 지원요청 바람! 다시 반복한다!`,JPN:`死傷者発生！　直ちに応援求む！　もう一度繰り返す！`,ENG:`Officer down! Calling for immediate back up! I repeat!`,TWN:`發生死傷！請求立即支援！重複一遍！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:null,text:{KOREA:`티, 팀장님...... 죄송...... 죄송합니다......`,JPN:`は、班長……す……すみません……`,ENG:`S-sir... I'm... sorry...`,TWN:`隊、隊長……對不起……對不起……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`말하지 말고 조금만 버텨! 지혈하고 어서 구급차를......`,JPN:`喋らなくていい、もう少し耐えろ！　止血してはやく救急班を……`,ENG:`Stop talking and hang on! Someone get me an ambulance before he bleeds out!`,TWN:`別說話，撐下去！先止血，救護車馬上就……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:null,text:{KOREA:`저...... 죽고 싶지...... 않아요......`,JPN:`し……死にたくない……です……`,ENG:`I... don't want... to die...`,TWN:`我……我不想死……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:null,text:{KOREA:`경찰들이란 참 안쓰러워.`,JPN:`警察というものは実に哀れだな。`,ENG:`I feel bad for you cops sometimes.`,TWN:`員警們可真可憐。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`나처럼 죽어 마땅한 범죄자도 마음대로 못 죽이고.`,JPN:`俺みたいに死んで当然な犯罪者すら、勝手に殺せないし。`,ENG:`You don't even get to kill criminals like me when you know we deserve it.`,TWN:`連我這種罪該萬死的犯罪者都不能隨便殺。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`인질 같은 게 뭐 그리 중요하다고 이렇게 다들 목숨을 버리는 건지. 안 그래?`,JPN:`所詮赤の他人にすぎない人質なんかのために命を捨てるなんて、バカな話だ。そう思わないか？`,ENG:`You have to lay down your lives for these mere hostages. What a waste, huh?`,TWN:`人質值得他們這樣犧牲自己的性命，是嗎？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`너......`,JPN:`お前……`,ENG:`You...`,TWN:`你……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`이런, 기껏 챙긴 돈이 피로 범벅이네.`,JPN:`おっと、せっかく手に入れた金が血まみれじゃないか。`,ENG:`Oh dear... All this money I stole got blood all over it.`,TWN:`該死，我的錢被血弄髒了。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}}];export{e as default};